import{_ as t,o as n,c as l,a2 as s}from"./chunks/framework.D36jym0Z.js";const u=JSON.parse('{"title":"Plugin Lifecycle","description":"","frontmatter":{},"headers":[],"relativePath":"platform-concepts/plugin-lifecycle.md","filePath":"platform-concepts/plugin-lifecycle.md","lastUpdated":1784629191000}'),a={name:"platform-concepts/plugin-lifecycle.md"};function i(o,e,c,p,d,r){return n(),l("div",null,[...e[0]||(e[0]=[s(`<h1 id="plugin-lifecycle" tabindex="-1">Plugin Lifecycle <a class="header-anchor" href="#plugin-lifecycle" aria-label="Permalink to &quot;Plugin Lifecycle&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Under development</p><p>The formal plugin lifecycle is being defined by the core team. This page describes the current working model as implemented for TokenPilot.</p></div><p>Every plugin on the LightMem2 platform follows a lifecycle managed by the core runtime. Understanding this lifecycle helps you reason about when your plugin code runs and what state is available.</p><h2 id="lifecycle-states" tabindex="-1">Lifecycle States <a class="header-anchor" href="#lifecycle-states" aria-label="Permalink to &quot;Lifecycle States&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    ┌──────────┐</span></span>
<span class="line"><span>                    │   None   │  Plugin not present on disk</span></span>
<span class="line"><span>                    └────┬─────┘</span></span>
<span class="line"><span>                         │ install</span></span>
<span class="line"><span>                    ┌────▼─────┐</span></span>
<span class="line"><span>                    │ Installed│  Plugin downloaded/config written</span></span>
<span class="line"><span>                    └────┬─────┘</span></span>
<span class="line"><span>                         │ enable</span></span>
<span class="line"><span>                    ┌────▼─────┐</span></span>
<span class="line"><span>                    │  Enabled  │  Plugin loaded, hooks registered</span></span>
<span class="line"><span>                    └────┬─────┘</span></span>
<span class="line"><span>                    ┌────┴─────┐</span></span>
<span class="line"><span>                    │           │</span></span>
<span class="line"><span>               ┌────▼─────┐     │</span></span>
<span class="line"><span>               │  Running  │     │  Active during a session</span></span>
<span class="line"><span>               └────┬─────┘     │</span></span>
<span class="line"><span>                    │           │</span></span>
<span class="line"><span>                    └────┬─────┘</span></span>
<span class="line"><span>                         │ disable / uninstall</span></span>
<span class="line"><span>                    ┌────▼─────┐</span></span>
<span class="line"><span>                    │ Disabled  │  Plugin unloaded</span></span>
<span class="line"><span>                    └──────────┘</span></span></code></pre></div><h2 id="lifecycle-hooks" tabindex="-1">Lifecycle Hooks <a class="header-anchor" href="#lifecycle-hooks" aria-label="Permalink to &quot;Lifecycle Hooks&quot;">​</a></h2><p>Each transition calls a plugin hook. Plugins implement the hooks they need:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Hook</th><th style="text-align:left;">Called When</th><th style="text-align:left;">Typical Use</th></tr></thead><tbody><tr><td style="text-align:left;"><code>onInstall</code></td><td style="text-align:left;">Plugin is first installed</td><td style="text-align:left;">Set up config, register with host</td></tr><tr><td style="text-align:left;"><code>onEnable</code></td><td style="text-align:left;">Plugin is enabled</td><td style="text-align:left;">Initialize state, start listeners</td></tr><tr><td style="text-align:left;"><code>onSessionStart</code></td><td style="text-align:left;">A new agent session begins</td><td style="text-align:left;">Reset per-session state</td></tr><tr><td style="text-align:left;"><code>onMessage</code></td><td style="text-align:left;">A message is about to be sent to the model</td><td style="text-align:left;">Modify context, apply policies</td></tr><tr><td style="text-align:left;"><code>onToolResult</code></td><td style="text-align:left;">A tool returns a result</td><td style="text-align:left;">Trim output, extract signals</td></tr><tr><td style="text-align:left;"><code>onSessionEnd</code></td><td style="text-align:left;">A session ends</td><td style="text-align:left;">Persist state, finalize metrics</td></tr><tr><td style="text-align:left;"><code>onDisable</code></td><td style="text-align:left;">Plugin is disabled</td><td style="text-align:left;">Stop listeners, release resources</td></tr><tr><td style="text-align:left;"><code>onUninstall</code></td><td style="text-align:left;">Plugin is removed</td><td style="text-align:left;">Clean up config, restore backups</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">TokenPilot implementation</p><p>TokenPilot&#39;s current implementation hooks into the host&#39;s event system via the adapter. The hook names above describe the logical lifecycle; the actual implementation uses host-specific mechanisms (OpenClaw plugin slots, Codex hooks, Claude Code MCP + SessionStart).</p></div><h2 id="plugin-conflict-and-ordering" tabindex="-1">Plugin Conflict and Ordering <a class="header-anchor" href="#plugin-conflict-and-ordering" aria-label="Permalink to &quot;Plugin Conflict and Ordering&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Under development</p><p>Rules for plugin execution order, conflict detection, and dependency resolution will be defined by the core team before additional plugins are released.</p></div><p>Currently, with only TokenPilot as the single official plugin, execution order is not a concern. When multiple plugins are active:</p><ul><li>Each plugin declares its <strong>execution phase</strong> (e.g., <code>pre-context</code>, <code>context-transform</code>, <code>post-response</code>)</li><li>Plugins in the same phase run in <strong>declared priority order</strong></li><li>The runtime detects <strong>conflicting data access</strong> and warns or errors at install time</li></ul><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/LightMem2/platform-concepts/configuration-model">Configuration Model</a> — how plugin config works</li><li><a href="/LightMem2/plugin-development/build-your-first-plugin">Build Your First Plugin</a> — implement lifecycle hooks</li><li><a href="/LightMem2/plugin-development/runtime-api">Runtime API</a> — the plugin programming interface</li></ul>`,15)])])}const f=t(a,[["render",i]]);export{u as __pageData,f as default};
